const timezone = "America/Sao_Paulo";

function safeString(v) {
  return v === undefined || v === null ? "" : String(v).trim();
}

function normalizeText(str) {
  return safeString(str)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function encodeQueryValue(v) {
  return encodeURIComponent(safeString(v));
}

function getZonedDateParts(date, timeZone) {
  const formatter = new Intl.DateTimeFormat("en-CA", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    weekday: "short",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });

  const parts = formatter.formatToParts(date);
  const obj = {};
  for (const part of parts) {
    if (part.type !== "literal") obj[part.type] = part.value;
  }
  return obj;
}

function buildSafeBaseDate(timeZone) {
  const now = new Date();
  const parts = getZonedDateParts(now, timeZone);
  return new Date(`${parts.year}-${parts.month}-${parts.day}T12:00:00`);
}

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function formatISODate(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function formatBRDate(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");
  return `${dd}/${mm}/${yyyy}`;
}

function isValidISODate(str) {
  return /^\d{4}-\d{2}-\d{2}$/.test(safeString(str));
}

const weekMap = {
  domingo: 0,
  segunda: 1,
  terca: 2,
  quarta: 3,
  quinta: 4,
  sexta: 5,
  sabado: 6,
};

const input = $json;

const requestedDayRaw = safeString(input.requested_day);
const requestedDateRaw = safeString(input.requested_date);
const senderName = safeString(input.sender_name);
const emailRaw = safeString(input.email).toLowerCase();

const baseDate = buildSafeBaseDate(timezone);

let requestedDate = null;
let scheduling_strategy = "";
let scheduling_reason = "";

// 1. Prioridade máxima: requested_date já preenchido
if (isValidISODate(requestedDateRaw)) {
  requestedDate = new Date(`${requestedDateRaw}T12:00:00`);
  scheduling_strategy = "requested_date";
  scheduling_reason = "Usou requested_date recebido da IA";
}

// 2. Segunda prioridade: requested_day
else if (requestedDayRaw) {
  const normalizedDay = normalizeText(requestedDayRaw);

  if (normalizedDay === "hoje") {
    requestedDate = baseDate;
    scheduling_strategy = "requested_day";
    scheduling_reason = "Usou requested_day = hoje";
  } else if (normalizedDay === "amanha" || normalizedDay === "amanhã") {
    requestedDate = addDays(baseDate, 1);
    scheduling_strategy = "requested_day";
    scheduling_reason = "Usou requested_day = amanhã";
  } else {
    const targetDay = weekMap[normalizedDay];

    if (targetDay !== undefined) {
      const currentDay = baseDate.getDay();
      let diff = (targetDay - currentDay + 7) % 7;

      if (diff === 0) diff = 7;

      requestedDate = addDays(baseDate, diff);
      scheduling_strategy = "requested_day";
      scheduling_reason = `Usou requested_day = ${requestedDayRaw}`;
    }
  }
}

// 3. Fallback automático: 48h pra frente
if (!requestedDate) {
  requestedDate = addDays(baseDate, 2);
  scheduling_strategy = "fallback_48h";
  scheduling_reason = "requested_day/requested_date ausentes ou inválidos. Aplicado fallback de 48h";
}

const requested_date_iso = formatISODate(requestedDate);
const requested_date_br = formatBRDate(requestedDate);

// Link de agendamento
const queryParts = [];

if (senderName) {
  queryParts.push(`name=${encodeQueryValue(senderName)}`);
}

if (emailRaw) {
  queryParts.push(`email=${encodeQueryValue(emailRaw)}`);
}

const bookingLinkBase = "https://agenda.convertix.app/r1";
const bookingLink = queryParts.length > 0
  ? `${bookingLinkBase}?${queryParts.join("&")}`
  : bookingLinkBase;

// Mensagem sugerida para o cliente
const bookingMessage =
  `Se quiser agilizar, você pode usar o link abaixo para escolher um horário de sua preferência, que fica mais rápido.\n` +
  `Link: ${bookingLink}`;

return [
  {
    json: {
      ...input,
      requested_date_iso,
      requested_date_br,
      scheduling_strategy,
      scheduling_reason,
      booking_link: bookingLink,
      booking_message: bookingMessage,
    },
  },
];

const TIMEZONE = 'America/Sao_Paulo';
const MIN_DIFF_MINUTES = 240;

// Se vier de um único item com array dentro, usa ele.
// Se vier item por item, também funciona.
let rawSlots = [];

if (items.length === 1 && Array.isArray(items[0].json)) {
  rawSlots = items[0].json;
} else if (items.length === 1 && Array.isArray(items[0].json.slots)) {
  rawSlots = items[0].json.slots;
} else {
  rawSlots = items.map(item => item.json);
}

function getShift(hour) {
  if (hour < 12) return 'manha';
  if (hour < 18) return 'tarde';
  return 'noite';
}

function formatHour(hour, minute) {
  if (minute === 0) {
    return `${hour}h`;
  }

  return `${hour}h${String(minute).padStart(2, '0')}`;
}

function getLocalParts(utcString, timeZone = TIMEZONE) {
  const date = new Date(utcString);

  const formatter = new Intl.DateTimeFormat('pt-BR', {
    timeZone,
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  });

  const parts = formatter.formatToParts(date);
  const get = (type) => parts.find(p => p.type === type)?.value || '';

  const weekdayRaw = get('weekday').toLowerCase();
  const weekday = weekdayRaw
    .replace('-feira', '')
    .replace('terca', 'terça')
    .replace('sabado', 'sábado');

  const day = get('day');
  const month = get('month');
  const year = get('year');
  const hour = Number(get('hour'));
  const minute = Number(get('minute'));

  const hourFormatted = formatHour(hour, minute);

  return {
    weekday,
    day,
    month,
    year,
    hour,
    minute,
    display: `${weekday}, ${day}/${month} às ${hourFormatted}`,
    shortDisplay: `${weekday} às ${hourFormatted}`,
    shift: getShift(hour),
  };
}


function getMinutesDiff(utcA, utcB) {
  const a = new Date(utcA).getTime();
  const b = new Date(utcB).getTime();
  return Math.abs((b - a) / 1000 / 60);
}

// Filtra só slots válidos e disponíveis
const slots = rawSlots
  .filter(slot => slot?.starts_at && (slot.available_bookings == null || slot.available_bookings > 0))
  .map(slot => {
    const local = getLocalParts(slot.starts_at);

    return {
      starts_at: slot.starts_at,
      ends_at: slot.ends_at || null,
      available_bookings: slot.available_bookings ?? null,
      local_weekday: local.weekday,
      local_day: local.day,
      local_month: local.month,
      local_year: local.year,
      local_hour: local.hour,
      local_minute: local.minute,
      local_shift: local.shift,
      display: local.display,
      short_display: local.shortDisplay,
    };
  })
  .sort((a, b) => new Date(a.starts_at) - new Date(b.starts_at));

if (slots.length === 0) {
  return [
    {
      json: {
        success: false,
        message: 'Nenhum horário disponível encontrado.',
        option_1: null,
        option_2: null,
        offered_slots: [],
      },
    },
  ];
}

const first = slots[0];
let second = null;

// 1. Procura slot com diferença mínima de 2h
second = slots.find((slot, index) => {
  if (index === 0) return false;
  return getMinutesDiff(first.starts_at, slot.starts_at) >= MIN_DIFF_MINUTES;
});

// 2. Se não achar, tenta slot no próximo turno
if (!second) {
  second = slots.find((slot, index) => {
    if (index === 0) return false;
    return slot.local_shift !== first.local_shift;
  });
}

// 3. Se ainda não achar, pega o próximo slot diferente do primeiro
if (!second) {
  second = slots.find((slot, index) => index > 0);
}

const offeredSlots = second ? [first, second] : [first];

return [
  {
    json: {
      success: true,
      timezone: TIMEZONE,
      rule: {
        first_option: 'slot mais próximo disponível',
        second_option: 'slot com diferença mínima de 4h; se não houver, próximo turno; se não houver, próximo slot disponível',
      },
      option_1: first
        ? {
            starts_at: first.starts_at,
            ends_at: first.ends_at,
            display: first.display,
            short_display: first.short_display,
            shift: first.local_shift,
          }
        : null,
      option_2: second
        ? {
            starts_at: second.starts_at,
            ends_at: second.ends_at,
            display: second.display,
            short_display: second.short_display,
            shift: second.local_shift,
          }
        : null,
      offered_slots: offeredSlots.map((slot, index) => ({
        option_id: `option_${index + 1}`,
        starts_at: slot.starts_at,
        ends_at: slot.ends_at,
        display: slot.display,
        short_display: slot.short_display,
        shift: slot.local_shift,
      })),
      whatsapp_message: second
        ? `Tenho dois horários a conversa com o especialista: \n*1. ${first.display}* ou \n*2. ${second.display}*. \nQual fica melhor para você?`
        : `Tenho somente um horário disponível para a conversa com nosso especialista: \n*1. ${first.display}*. \nEsse horário funciona para você?`,
    },
  },
];
